Here's how to implement all three requirements:

### 1. Custom "Cancel" back button on `EditProductPage`

```xml
<!-- EditProductPage.xaml -->
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.EditProductPage">

    <Shell.BackButtonBehavior>
        <BackButtonBehavior TextOverride="Cancel"
                           Command="{Binding BackCommand}" />
    </Shell.BackButtonBehavior>

    <!-- your form content -->
</ContentPage>
```

### 2. ViewModel with confirmation logic

```csharp
// EditProductViewModel.cs
public partial class EditProductViewModel : ObservableObject
{
    [ObservableProperty]
    bool hasUnsavedChanges;

    public ICommand BackCommand { get; }

    public EditProductViewModel()
    {
        BackCommand = new AsyncRelayCommand(OnBackAsync);
    }

    async Task OnBackAsync()
    {
        if (HasUnsavedChanges)
        {
            bool discard = await Shell.Current.DisplayAlert(
                "Unsaved Changes",
                "You have unsaved changes. Discard them?",
                "Discard", "Stay");

            if (!discard)
                return; // user chose "Stay" — do nothing
        }

        await Shell.Current.GoToAsync("..");
    }
}
```

### 3. Guard the hardware/swipe back gesture in `AppShell`

The custom button handles tap, but users can also swipe back or press the hardware back button. Guard that in `AppShell.xaml.cs`:

```csharp
// AppShell.xaml.cs
protected override async void OnNavigating(ShellNavigatingEventArgs args)
{
    base.OnNavigating(args);

    if (args.Source != ShellNavigationSource.Pop)
        return;

    if (Shell.Current.CurrentPage?.BindingContext
            is EditProductViewModel vm && vm.HasUnsavedChanges)
    {
        var deferral = args.GetDeferral();

        bool discard = await Shell.Current.DisplayAlert(
            "Unsaved Changes",
            "You have unsaved changes. Discard them?",
            "Discard", "Stay");

        if (!discard)
            args.Cancel();

        deferral.Complete();
    }
}
```

**Key points:**
- `BackButtonBehavior` with `TextOverride="Cancel"` replaces the arrow with text and binds to your own command.
- The `BackCommand` shows the dialog and only calls `GoToAsync("..")` if confirmed.
- `OnNavigating` with `GetDeferral()` catches swipe/hardware back — `GetDeferral()` is required because `DisplayAlert` is async.
- Both paths check `HasUnsavedChanges` so clean forms navigate back immediately.
